/**
 * Typed agent event vocabulary. The wire format flowing through
 * `/api/studio/events` (push, poll, SSE stream) is constrained to this
 * union. Both bitfab-web and bitfab-plugin-lib reference these types.
 *
 * Add a new event type by extending `AgentEventDataMap`. Producers
 * (plugins, server) get full type checking on the data shape; consumers
 * (browser hook subscribers, plugin pollers) narrow on `event.type`.
 */
export interface AgentEventDataMap {
    "agent:navigate": {
        path: string;
    };
    "studio:return-to-agent": Record<string, never>;
    "studio:edit-with-agent": {
        datasetId: string;
    };
    "studio:session-ended": Record<string, never>;
    "studio:auth-required": Record<string, never>;
    "studio:authenticated": Record<string, never>;
    /**
     * Plugin-to-browser: the agent has finished its work and the Studio session
     * can be closed. The browser shows a "session complete" view with the
     * optional `message` and a Close button. Fired by `closeStudio.js`.
     */
    "agent:close-studio": {
        message?: string;
    };
    /**
     * Browser-to-plugin: the user clicked a region of the rendered template
     * preview. Anchor attributes are resolved against the template-anchor
     * catalog (`bitfab-web/src/app/lib/domains/templateAnchors.ts`); unknown
     * values are dropped to undefined while `rawText` + `selector` always flow
     * through so the editing agent can disambiguate.
     *
     * Iterables: `iterIndex` carries the resolved value of `[N]` when the
     * click landed on an iteration body (see `data-iter-index` on the loop
     * wrapper). Substitute it into `fieldPath` (e.g.
     * `metadata.prompt.messages[N].content` with `iterIndex: 3` ->
     * `metadata.prompt.messages[3].content`).
     *
     * `activeTemplateId` is the studio's current template filter (e.g.
     * `"all"` or a renderer type like `"response"`). Tells the editing agent
     * which scope the user is in when they click, so an edit can target the
     * right template even when multiple span types share a section path.
     */
    "studio:element-clicked": {
        traceId: string;
        spanId?: string;
        spanType?: string;
        sectionPath?: string;
        fieldPath?: string;
        iterIndex?: number;
        activeTemplateId?: string;
        rawText: string;
        selector: string;
    };
    /**
     * Browser-to-plugin: the user's current viewport in the template preview.
     * Fires on selection changes (span vs. trace) and shadow-root `<details>`
     * toggles. The editing agent reads the latest `focusChanged` to know what
     * the user is looking at when interpreting follow-up instructions.
     *
     * `spanId` is null when the user is on the trace overview. `viewMode` is
     * derivable from `spanId` but kept explicit because the consumer is an
     * LLM, and explicit signals beat implication.
     */
    focusChanged: {
        traceId: string;
        spanId: string | null;
        viewMode: "trace" | "span";
        expandedSections: string[];
    };
    /**
     * Plugin-to-browser: an `update_template` MCP call has started. The browser
     * shows a "Coding agent currently editing ..." status banner between this
     * event and the matching `editEnded`, and outlines the targeted element
     * in the shadow root. Pushed by the plugin's MCP server wrapper around
     * the `update_template` tool, scoped to the active preview session that
     * `startTemplatePreview` recorded in `~/.bitfab/active-preview-session`.
     *
     * `anchor` carries the specific region being edited (resolved against the
     * template-anchor catalog). When present, the banner names the path and
     * outlines the matching `[data-field-path]` / `[data-section]` element.
     * Forward-compat: producers that don't know the anchor can omit it; the
     * browser falls back to the user's most recent click on this span type.
     */
    editStarted: {
        spanType: string;
        traceFunctionKey: string | null;
        /** Display name for the host agent (e.g. Claude, Codex). From plugin. */
        agentLabel?: string;
        anchor?: {
            sectionPath?: string;
            fieldPath?: string;
            iterIndex?: number;
            rawText?: string;
        };
    };
    /**
     * Plugin-to-browser: the `update_template` call returned. `success` carries
     * the proxy result; on failure, `summary` describes what went wrong. The
     * browser drops the status banner and (on success) briefly flashes the
     * outlined section before fading it out. `anchor` mirrors the editStarted
     * payload so the banner can re-key its highlight on rapid back-to-back edits.
     */
    editEnded: {
        spanType: string;
        traceFunctionKey: string | null;
        success: boolean;
        summary: string;
        anchor?: {
            sectionPath?: string;
            fieldPath?: string;
            iterIndex?: number;
            rawText?: string;
        };
    };
    /**
     * Server-to-browser: the eval assistant agent started or finished a tool
     * call. The Studio home page shows this as a live status indicator inside
     * the "Coding agent" panel so the user knows the agent is working and
     * what it is doing right now.
     */
    "agent:activity": {
        action: "started" | "completed" | "failed";
        tool: string;
        displayName: string;
    };
    /**
     * Browser-to-plugin: the user navigated to a new page inside Studio.
     * Fires on every client-side route change so the editing agent always
     * knows where the user is looking. `path` is the pathname without the
     * session query parameter (e.g. `/studio/trace-functions/my-func/template-preview`).
     */
    "studio:navigated": {
        path: string;
    };
    /**
     * Server-emitted: the plugin (via `create_trace_plan`) recorded a fresh
     * trace plan. Lets Studio's live activity indicator show "trace plan
     * captured for X" without waiting for the user to open it.
     */
    "tracePlan:created": {
        planId: string;
        traceFunctionKey: string | null;
        language: "python" | "typescript" | "ruby" | "go";
        capturedSpanCount: number;
    };
    /**
     * Server-emitted: the user landed on `/trace-plans/latest`, which resolves
     * to their most recent plan. Studio uses this to surface a "viewing last
     * trace plan" indicator distinct from a fresh capture.
     */
    "tracePlan:latestOpened": {
        planId: string;
        traceFunctionKey: string | null;
    };
    /**
     * Server-emitted: the trace plan detail page mounted. Distinct from
     * `tracePlan:latestOpened` so we can count direct visits vs. quick-opens.
     */
    "tracePlan:viewerOpened": {
        planId: string;
    };
    /**
     * Server-emitted: the user clicked Confirm in the trace planner. Pairs
     * with the existing `confirm` API call and lets Studio reflect plan
     * acceptance in real time.
     */
    "tracePlan:confirmed": {
        planId: string;
        traceFunctionKey: string | null;
    };
    /**
     * Server-emitted: the user cancelled the trace planner (Esc or close).
     * Lets Studio reflect that the plugin's blocking handoff just unblocked
     * with no plan applied.
     */
    "tracePlan:cancelled": {
        planId: string;
        traceFunctionKey: string | null;
    };
}
export type AgentEventType = keyof AgentEventDataMap & string;
export type AgentEventPayload = {
    [K in keyof AgentEventDataMap]: {
        type: K;
        data: AgentEventDataMap[K];
    };
}[keyof AgentEventDataMap];
export type AgentEvent = {
    [K in keyof AgentEventDataMap]: {
        id: string;
        type: K;
        data: AgentEventDataMap[K];
    };
}[keyof AgentEventDataMap];
